settings.custom_liquid:
{% if collection.metafields.custom.bild != blank %}
  <div 
    class="custom-background-section"
    style="background-image: url({{ collection.metafields.custom.bild | image_url: width: 2048 }});"
  >
    {% if collection.metafields.custom.text != blank %}
      <div class="custom-background-text">
        {{ collection.metafields.custom.text }}
      </div>
    {% endif %}
  </div>
{% endif %}

<style>
  .custom-background-section {
    margin-top: -40px;
    position: relative;
    display: flex;
    justify-content: flex-end; /* Text nach rechts */
    align-items: center;       /* vertikal zentrieren */
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    height: 500px;
    width: 100vw;
    padding: 40px;
    color: white;
  }
.custom-background-text {
    width: 40%; /* nimmt etwa die rechte Hälfte ein */
    background: rgba(0, 0, 0, 0.25);
    padding: 40px;
    border-radius: 12px;
    font-size: 2.2rem;
    font-family: lora;
    line-height: 2;
    text-align: left;
    margin-right: 5%;
  }

  /* Responsive Anpassung */
  @media (max-width: 768px) {
    .custom-background-section {
      display: none;
    }
    .custom-background-text {
      display: none;
    }
  }
</style>
